useAINexusStore.test.ts.content:
import { describe, it, expect, beforeEach } from 'vitest';
import { useAINexusStore } from '../../../store/useAINexusStore';

describe('useAINexusStore', () => {
  beforeEach(() => {
    useAINexusStore.setState({
      messages: [
        { id: 'msg-1', role: 'assistant', content: 'Hello. Nexus Core is synchronized. How shall we begin?' }
      ],
      isGenerating: false,
      modelVersion: 'basic',
    });
  });

  it('should have default state', () => {
    const state = useAINexusStore.getState();
    expect(state.messages).toHaveLength(1);
    expect(state.isGenerating).toBe(false);
    expect(state.modelVersion).toBe('basic');
  });

  it('should add a message via addMessage', () => {
    const { addMessage } = useAINexusStore.getState();
    addMessage({ id: 'msg-2', role: 'user', content: 'Hello!' });

    const state = useAINexusStore.getState();
    expect(state.messages).toHaveLength(2);
    expect(state.messages[1]?.content).toBe('Hello!');
  });

  it('should set isGenerating', () => {
    const { setIsGenerating } = useAINexusStore.getState();
    setIsGenerating(true);
    expect(useAINexusStore.getState().isGenerating).toBe(true);
    setIsGenerating(false);
    expect(useAINexusStore.getState().isGenerating).toBe(false);
  });

  it('should set modelVersion', () => {
    const { setModelVersion } = useAINexusStore.getState();
    setModelVersion('latest');
    expect(useAINexusStore.getState().modelVersion).toBe('latest');
  });

  it('should clear messages on clearMessages', () => {
    const { addMessage, clearMessages } = useAINexusStore.getState();
    addMessage({ id: 'msg-2', role: 'user', content: 'Test' });
    clearMessages();

    const state = useAINexusStore.getState();
    expect(state.messages).toHaveLength(1);
    expect(state.messages[0]?.role).toBe('assistant');
  });
});

useAppStore.test.ts.content:
import { describe, it, expect, beforeEach } from 'vitest'
import { useAppStore } from '@/store/useAppStore'

describe('useAppStore', () => {
  beforeEach(() => {
    // Reset state before each test
    useAppStore.setState({
      activeScreen: 'dashboard',
      theme: 'chatgpt',
      isLoggedIn: false,
      isSidebarExpanded: false,
      isMobileSidebarOpen: false,
      activeModelId: 'chatgpt',
      pendingModelId: null,
      activeFolder: null,
    })
  })

  it('should change active screen and reset active folder', () => {
    useAppStore.setState({ activeFolder: 'test-folder' })
    useAppStore.getState().setActiveScreen('library')

    expect(useAppStore.getState().activeScreen).toBe('library')
    expect(useAppStore.getState().activeFolder).toBeNull()
  })

  it('should close mobile sidebar when changing screen', () => {
    useAppStore.setState({ isMobileSidebarOpen: true })
    useAppStore.getState().setActiveScreen('prompts')

    expect(useAppStore.getState().isMobileSidebarOpen).toBe(false)
  })

  it('should close mobile sidebar via closeMobileSidebar action', () => {
    useAppStore.setState({ isMobileSidebarOpen: true })
    useAppStore.getState().closeMobileSidebar()

    expect(useAppStore.getState().isMobileSidebarOpen).toBe(false)
  })

  it('should respect partialize during persistence', () => {
    // This is hard to test directly without mocking the persist middleware,
    // but we can verify the state fields manually.
    const state = useAppStore.getState()
    const persist = (useAppStore as any).persist

    if (persist && persist.options && persist.options.partialize) {
      const partial = persist.options.partialize(state)
      expect(partial).toHaveProperty('theme')
      expect(partial).toHaveProperty('isLoggedIn')
      expect(partial).toHaveProperty('activeModelId')
      expect(Object.keys(partial)).toHaveLength(3)
    }
  })
})

useLibraryStore.test.ts.content:
import { describe, it, expect, beforeEach, vi } from 'vitest'
import { useLibraryStore } from '@/store/useLibraryStore'
import * as actions from '@/actions/library'

// Mock the server actions
vi.mock('@/actions/library', () => ({
  loadUserData: vi.fn(),
  createFolder: vi.fn(),
  deleteFolder: vi.fn(),
  upsertItem: vi.fn(),
  softDeleteItem: vi.fn(),
  freezeItem: vi.fn(),
}))

describe('useLibraryStore', () => {
  beforeEach(() => {
    vi.clearAllMocks()
    useLibraryStore.setState({
      libraryFolders: [],
      promptFolders: [],
      items: [],
      isLoading: false,
    })
  })

  it('should implement optimistic createFolder and update with server result', async () => {
    const mockCreatedFolder = { id: 'real-id', name: 'New Folder', type: 'library' }
    vi.mocked(actions.createFolder).mockResolvedValue(mockCreatedFolder as any)

    const promise = useLibraryStore.getState().createFolder({ name: 'New Folder', type: 'library', iconIndex: 0, parentId: null, level: 0 })

    // Check optimistic state
    expect(useLibraryStore.getState().libraryFolders).toHaveLength(1)
    expect(useLibraryStore.getState().libraryFolders[0]!.id).toBeDefined()

    await promise

    // Check final state
    expect(useLibraryStore.getState().libraryFolders[0]!.id).toBe('real-id')
  })

  it('should rollback createFolder on server error', async () => {
    vi.mocked(actions.createFolder).mockRejectedValue(new Error('Server error'))

    try {
      await useLibraryStore.getState().createFolder({ name: 'New Folder', type: 'library', iconIndex: 0, parentId: null, level: 0 })
    } catch (e) {
      // expected
    }

    expect(useLibraryStore.getState().libraryFolders).toHaveLength(0)
  })

  it('should soft delete item optimistically', async () => {
    const originalItem = { id: 'item-1', title: 'Test', type: 'chat', folderId: null, content: '' }
    useLibraryStore.setState({ items: [originalItem as any] })

    const promise = useLibraryStore.getState().deleteItem('item-1')

    expect(useLibraryStore.getState().items[0]!.deletedAt).toBeDefined()

    await promise
    expect(actions.softDeleteItem).toHaveBeenCalledWith('item-1')
  })

  it('should load and split data correctly', async () => {
    const mockData = {
      libraryFolders: [{ id: 'l1', type: 'library' }],
      promptFolders: [{ id: 'p1', type: 'prompt' }],
      items: [{ id: 'i1' }]
    }
    vi.mocked(actions.loadUserData).mockResolvedValue(mockData as any)

    await useLibraryStore.getState().loadData()

    expect(useLibraryStore.getState().libraryFolders).toHaveLength(1)
    expect(useLibraryStore.getState().promptFolders).toHaveLength(1)
    expect(useLibraryStore.getState().items).toHaveLength(1)
  })
})

usePromptStore.test.ts.content:
import { describe, it, expect, beforeEach } from 'vitest';
import { usePromptStore } from '../../../store/usePromptStore';
import type { Folder, Item } from '@brainbox/types';

const mockFolder: Folder = {
  id: 'f1',
  name: 'Test Folder',
  type: 'prompt',
  iconIndex: 0,
  level: 0,
  parentId: null,
};

const mockItem: Item = {
  id: 'i1',
  folderId: 'f1',
  title: 'Test Item',
  description: 'Test description',
  content: 'Test Content',
  type: 'prompt',
};

describe('usePromptStore', () => {
  beforeEach(() => {
    // Reset state before each test
    usePromptStore.setState({
      folders: [],
      items: [],
      activeFolder: null,
    });
  });

  it('should initialize with empty state', () => {
    const state = usePromptStore.getState();
    expect(state.folders).toEqual([]);
    expect(state.items).toEqual([]);
    expect(state.activeFolder).toBeNull();
  });

  it('should add a folder', () => {
    const { addFolder } = usePromptStore.getState();
    addFolder(mockFolder);

    expect(usePromptStore.getState().folders).toHaveLength(1);
    expect(usePromptStore.getState().folders[0]).toEqual(mockFolder);
  });

  it('should add an item', () => {
    const { addItem } = usePromptStore.getState();
    addItem(mockItem);

    expect(usePromptStore.getState().items).toHaveLength(1);
    expect(usePromptStore.getState().items[0]).toEqual(mockItem);
  });

  it('should update a folder', () => {
    const { addFolder, updateFolder } = usePromptStore.getState();
    addFolder(mockFolder);
    updateFolder('f1', { name: 'Updated Name' });

    const updated = usePromptStore.getState().folders.find(f => f.id === 'f1');
    expect(updated?.name).toBe('Updated Name');
  });

  it('should update an item', () => {
    const { addItem, updateItem } = usePromptStore.getState();
    addItem(mockItem);
    updateItem('i1', { content: 'Updated Content' });

    const updated = usePromptStore.getState().items.find(i => i.id === 'i1');
    expect(updated?.content).toBe('Updated Content');
  });

  it('should delete a folder', () => {
    const { addFolder, deleteFolder } = usePromptStore.getState();
    addFolder(mockFolder);
    deleteFolder('f1');

    expect(usePromptStore.getState().folders).toHaveLength(0);
  });

  it('should delete an item', () => {
    const { addItem, deleteItem } = usePromptStore.getState();
    addItem(mockItem);
    deleteItem('i1');

    expect(usePromptStore.getState().items).toHaveLength(0);
  });

  it('should set active folder', () => {
    const { setActiveFolder } = usePromptStore.getState();
    setActiveFolder('f1');

    expect(usePromptStore.getState().activeFolder).toBe('f1');
  });

  it('should bulk set folders and items', () => {
    const { setFolders, setItems } = usePromptStore.getState();
    setFolders([mockFolder]);
    setItems([mockItem]);

    expect(usePromptStore.getState().folders).toEqual([mockFolder]);
    expect(usePromptStore.getState().items).toEqual([mockItem]);
  });
});

rate-limit.test.ts.content:
import { describe, it, expect, beforeEach, vi } from 'vitest';
import { isRateLimited } from '../../../lib/rate-limit';

describe('rateLimit', () => {
  beforeEach(() => {
    vi.useFakeTimers();
  });

  it('should allow requests within limit', async () => {
    const key = `test-1-${Date.now()}`;
    // isRateLimited returns true if BLOCKED, false if ALLOWED
    const blocked1 = isRateLimited(key, 2, 60000);
    const blocked2 = isRateLimited(key, 2, 60000);

    expect(blocked1).toBe(false);
    expect(blocked2).toBe(false);
  });

  it('should block requests exceeding limit', async () => {
    const key = `test-2-${Date.now()}`;
    isRateLimited(key, 1, 60000);
    const blocked = isRateLimited(key, 1, 60000);

    expect(blocked).toBe(true);
  });

  it('should reset after window expires', async () => {
    const key = `test-3-${Date.now()}`;
    isRateLimited(key, 1, 60000);

    // Fast forward time by 61 seconds
    vi.advanceTimersByTime(61 * 1000);

    const blocked = isRateLimited(key, 1, 60000);
    expect(blocked).toBe(false);
  });
});

