import { NextResponse } from 'next/server';

/**
 * GET /api/chats/[id]
 * Demonstrates Next.js 16.2 Async Params pattern.
 */
export async function GET(
  request: Request,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params;

  return NextResponse.json({ 
    id, 
    message: `Chat ${id} retrieved successfully` 
  });
}

import { createClient } from '@/lib/supabase/server';
import { NextResponse } from 'next/server';
import { ItemSchema } from '@brainbox/types';
import { logger } from '@brainbox/utils';

import { isRateLimited } from '@/lib/rate-limit';

const RATE_LIMIT = 30;
const RATE_WINDOW_MS = 60 * 1000;

/**
 * Extension Sync API (ADR-012)
 * Receives captured chats from the Chrome Extension with isolated platform tracking.
 */
export async function POST(request: Request) {
  try {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    // Rate limit: 30 req/min per user
    if (isRateLimited(user.id)) {
      logger.warn('API:extension:sync', 'Rate limit exceeded', { userId: user.id })
      return NextResponse.json({ error: 'Too many requests' }, { status: 429 });
    }

    const body = await request.json();

    // Validate incoming data (Chat objects from extension)
    const result = ItemSchema.safeParse({
      ...body,
      type: 'chat',
    });

    if (!result.success) {
      logger.warn('API:extension:sync', 'Validation failed', result.error.flatten());
      return NextResponse.json({ error: 'Validation failed', details: result.error.flatten() }, { status: 400 });
    }

    const { data: validatedData } = result;

    // Save to Supabase (map camelCase to snake_case)
    const { data, error } = await supabase
      .from('items')
      .upsert({
        id: validatedData.id,
        user_id: user.id,
        title: validatedData.title,
        description: validatedData.description,
        type: validatedData.type,
        folder_id: validatedData.folderId,
        content: validatedData.content,
        theme: validatedData.theme || validatedData.platform, // Fallback to platform if theme missing
        tags: validatedData.tags,
        is_frozen: validatedData.isFrozen,
        deleted_at: validatedData.deletedAt,
        // Extension Specific Fields
        source_id: validatedData.sourceId,
        platform: validatedData.platform,
        url: validatedData.url,
        messages: validatedData.messages
      }, {
        onConflict: 'user_id, source_id, platform'
      })
      .select()
      .single();

    if (error) {
      logger.error('API:extension:sync', 'Database upsert failed', error);
      throw error;
    }

    return NextResponse.json({ success: true, item: data });

  } catch (error: any) {
    logger.error('API:extension:sync', 'Sync failed', error);
    return NextResponse.json(
      { error: error.message || 'Internal Server Error' }, 
      { status: error.status || 500 }
    );
  }
}

import { NextResponse } from 'next/server'
import { createClient } from '@/lib/supabase/server'
import { z } from 'zod'

const chunkSchema = z.object({
  title: z.string().min(1).max(200),
  content: z.string(),
  url: z.string().url().optional(),
  type: z.enum(['code', 'text', 'quote']).default('text'),
  folderId: z.string().uuid().nullable().optional()
})

/**
 * Extension Chunks API
 * Receives snippets captured by the user from AI platforms.
 */
export async function POST(request: Request) {
  try {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const body = await request.json()
    const result = chunkSchema.safeParse(body)

    if (!result.success) {
      return NextResponse.json({ error: 'Invalid data', details: result.error.flatten() }, { status: 400 })
    }

    // Chunks are stored in the 'items' table with type 'chat' or 'prompt'? 
    // Actually, BrainBox reference uses 'library' vs 'prompt' folders.
    // We'll store them as 'chat' items for now but tagged as snippets.
    const { data, error } = await supabase
      .from('items')
      .insert({
        user_id: user.id,
        title: result.data.title,
        content: result.data.content,
        type: 'chat', // default to chat for the library
        folder_id: result.data.folderId || null,
        url: result.data.url,
        tags: ['snippet', result.data.type],
        theme: 'gemini' // default brainbox theme
      })
      .select()
      .single()

    if (error) throw error

    return NextResponse.json({ success: true, chunk: data })

  } catch (error: any) {
    return NextResponse.json(
      { error: error.message || 'Internal Server Error' }, 
      { status: 500 }
    )
  }
}

import { NextResponse } from 'next/server'
import { createClient } from '@/lib/supabase/server'
import { logger } from '@brainbox/utils'
import { z } from 'zod'

const extensionErrorSchema = z.object({
  platform: z.string().optional(),
  message: z.string(),
  stack: z.string().optional(),
  url: z.string().optional(),
  version: z.string().optional(),
  context: z.record(z.unknown()).optional()
})

/**
 * Extension Error Monitoring API
 * Passive observation of failures in the extension adapters.
 */
export async function POST(request: Request) {
  try {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    // We allow logging even for unauthenticated users if the extension is failing at login,
    // but we tag it appropriately.
    const body = await request.json()
    const result = extensionErrorSchema.safeParse(body)

    if (!result.success) {
      return NextResponse.json({ error: 'Invalid error report' }, { status: 400 })
    }

    const { platform, message, stack, url, version, context } = result.data

    logger.error('EXT_MONITOR', `Extension Error [${platform || 'unknown'}]: ${message}`, {
      userId: user?.id || 'anonymous',
      platform,
      stack,
      url,
      version,
      context
    })

    // In a real Sentry setup, we would capture the exception here
    // captureException(new Error(message), { extra: { ...context, platform, userId: user?.id } })

    return NextResponse.json({ success: true })

  } catch (error) {
    // Avoid circular logging if logger fails
    console.error('[CRITICAL_EXT_MONITOR_FAILURE]', error)
    return NextResponse.json({ error: 'Internal failure' }, { status: 500 })
  }
}

import { NextResponse } from 'next/server'
import { createClient } from '@/lib/supabase/server'

/**
 * Extension Prompts API
 * Returns the user's saved prompts for injection into AI platforms.
 */
export async function GET() {
  try {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    // Fetch items of type 'prompt'
    const { data, error } = await supabase
      .from('items')
      .select('*')
      .eq('user_id', user.id)
      .eq('type', 'prompt')
      .order('created_at', { ascending: false })

    if (error) {
      throw error
    }

    return NextResponse.json({ success: true, prompts: data })

  } catch (error: any) {
    return NextResponse.json(
      { error: error.message || 'Internal Server Error' }, 
      { status: 500 }
    )
  }
}

