@import "tailwindcss";
@import "tw-animate-css";
@import "shadcn/tailwind.css";
@import "../../../packages/config/styles/brainbox.css";

/* ── Tailwind v4 Monorepo Sources ── */
@source "../../packages/ui/src/**/*.{ts,tsx}";
@source "../../packages/utils/src/**/*.{ts,tsx}";

/* ── BrainBox Font ── */
@theme {
  --font-sans: var(--font-inter), ui-sans-serif, system-serif, sans-serif;
}

/* ── shadcn/ui CSS Variables ── */
@custom-variant dark (&:is(.dark *));

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-border: var(--border);
  --color-ring: var(--ring);
  --radius-sm: calc(var(--radius) * 0.6);
  --radius-md: calc(var(--radius) * 0.8);
  --radius-lg: var(--radius);
  --color-sidebar: var(--sidebar);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-ring: var(--sidebar-ring);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
}

/* BrainBox is dark-only */
:root {
  --radius: 0.5rem;
  --background: oklch(0.06 0 0);
  --foreground: oklch(0.985 0 0);
  --card: oklch(0.12 0 0);
  --card-foreground: oklch(0.985 0 0);
  --popover: oklch(0.1 0 0);
  --popover-foreground: oklch(0.985 0 0);
  --primary: oklch(0.922 0 0);
  --primary-foreground: oklch(0.145 0 0);
  --secondary: oklch(0.2 0 0);
  --secondary-foreground: oklch(0.985 0 0);
  --muted: oklch(0.2 0 0);
  --muted-foreground: oklch(0.708 0 0);
  --accent: oklch(0.2 0 0);
  --accent-foreground: oklch(0.985 0 0);
  --destructive: oklch(0.6 0.2 25);
  --border: oklch(1 0 0 / 8%);
  --input: oklch(1 0 0 / 10%);
  --ring: oklch(0.5 0 0);

  --sidebar: oklch(0.1 0 0);
  --sidebar-foreground: oklch(0.985 0 0);
  --sidebar-primary: oklch(0.922 0 0);
  --sidebar-primary-foreground: oklch(0.145 0 0);
  --sidebar-accent: oklch(0.2 0 0);
  --sidebar-accent-foreground: oklch(0.985 0 0);
  --sidebar-border: oklch(1 0 0 / 8%);
  --sidebar-ring: oklch(0.5 0 0);

  /* ── BrainBox Platform Accent Colors ── */
  /* Used as: var(--color-acc-chatgpt), var(--color-acc-claude), etc. */
  --color-acc-chatgpt:   #10a37f;  /* OpenAI green */
  --color-acc-claude:    #d97757;  /* Anthropic warm orange */
  --color-acc-gemini:    #8ab4f8;  /* Google blue */
  --color-acc-mistral:   #7c3aed;  /* Mistral violet */
  --color-acc-grok:      #e5e5e5;  /* xAI light grey */
  --color-acc-perplexity:#20b2aa;  /* Perplexity teal */
  --color-acc-deepseek:  #3b82f6;  /* DeepSeek blue */
  --color-acc-neutral:   #6b7280;  /* fallback neutral */
}

/* ── BrainBox Custom Classes (Inherited from @brainbox/config) ── */
html,
body {
  background-color: #000000;
  color: #ffffff;
  overflow: hidden;
  position: fixed;
  inset: 0;
  width: 100%;
  height: 100%;
  margin: 0;
  padding: 0;
}

#root,
main {
  height: 100%;
  width: 100%;
  overflow: hidden;
}

/* Scrollbar hidden */
::-webkit-scrollbar {
  display: none;
}
* {
  scrollbar-width: none;
}

/* h-dvh for mobile viewport fix */
.h-dvh {
  height: 100dvh;
}

@layer base {
  * {
    @apply border-border;
  }
  body {
    @apply bg-background text-foreground antialiased;
  }
}

